        """Completed orders don't block token reuse — status filter is correct"""
        for t in range(1, 100):
            db.add(make_platform_order(token_number=t, restaurant_id=restaurant_id,
                                       status="completed"))
        db.commit()
        token = generate_token_number(db, restaurant_id)
        assert 1 <= token <= 99  # full range available

    def test_token_range_boundary(self, db, restaurant_id):
        """With 98 active tokens, still finds last slot"""
        for t in range(1, 99):
            db.add(make_platform_order(token_number=t, restaurant_id=restaurant_id,
                                       status="pending"))
        db.commit()
        token = generate_token_number(db, restaurant_id)
